// ==========================================
// INSTAGRAM EVENT CLASSIFIER
// Parses Meta webhook payload into clean event
// ==========================================
const body = $input.item.json.body || $input.item.json;
const entry = body.entry?.[0] || {};
const changes = entry.changes?.[0] || {};
const field = changes.field || 'unknown';
const value = changes.value || {};

let event_type = 'unknown';
let comment_id = '';
let comment_text = '';
let commenter_id = '';
let commenter_username = '';
let media_id = '';
let parent_id = '';
let is_reply = false;

// Comment on post
if (field === 'comments') {
  event_type = 'comment';
  comment_id = value.id || '';
  comment_text = value.text || '';
  commenter_id = value.from?.id || '';
  commenter_username = value.from?.username || '';
  media_id = value.media?.id || '';
  parent_id = value.parent_id || '';
  is_reply = !!parent_id;
}
// Mention in caption or comment
else if (field === 'mentions') {
  event_type = 'mention';
  comment_id = value.comment_id || '';
  comment_text = value.text || '';
  commenter_id = value.from?.id || '';
  commenter_username = value.from?.username || '';
  media_id = value.media_id || '';
}
// Story mention
else if (field === 'story_insights' || value.story_id) {
  event_type = 'story_mention';
  commenter_id = value.from?.id || '';
  commenter_username = value.from?.username || '';
}
// DM (messaging)
else if (field === 'messages' || body.messaging) {
  const msg = body.messaging?.[0] || value;
  event_type = 'dm';
  commenter_id = msg.sender?.id || '';
  comment_text = msg.message?.text || '';
}

// Skip our own replies
const our_ig_id = $env.INSTAGRAM_PAGE_ID || '';
if (commenter_id === our_ig_id) {
  return { json: { skip: true, reason: 'own_reply' } };
}

// Skip replies to replies (only reply to top-level comments)
if (is_reply) {
  return { json: { skip: true, reason: 'is_reply_to_reply' } };
}

return {
  json: {
    skip: false,
    event_type,
    comment_id,
    comment_text,
    commenter_id,
    commenter_username,
    media_id,
    parent_id,
    timestamp: new Date().toISOString()
  }
};

// ==========================================
// SMART REPLY GENERATOR
// Generates engaging reply based on comment intent
// Goal: Drive commenter to DM for sales conversion
// ==========================================
const text = $json.comment_text || '';
const username = $json.commenter_username || '';
const textLower = text.toLowerCase();

// === INTENT DETECTION ===
let intent = 'general';
let reply = '';
let should_dm = false;

// Price inquiry
if (textLower.match(/كم|سعر|تكلف|بكم|الاشتراك|رسوم|مجان/)) {
  intent = 'price_inquiry';
  reply = `@${username} أرسلك التفاصيل على الخاص 🔥`;
  should_dm = true;
}
// Interest / want to join
else if (textLower.match(/ابغى|أبغى|ابي|أبي|اشترك|سجل|ابدأ|أبدأ|كيف|طريقة/)) {
  intent = 'interest';
  reply = `@${username} حياك! أرسلك كل شيء بالخاص الحين 🚀`;
  should_dm = true;
}
// Positive reaction
else if (textLower.match(/ماشاء الله|جميل|رائع|حلو|الله|ممتاز|يجنن|❤|🔥|👏|😍|💪/)) {
  intent = 'positive';
  const positiveReplies = [
    `@${username} الله يسعدك! جرّبت تمعّن؟ 28 يوم تغيّر علاقتك بالقرآن ✨`,
    `@${username} يسلمك ربي 🤍 لو تبغى تجربة مجانية أرسلني خاص`,
    `@${username} شكراً لك! تمعّن غيّر حياة ناس كثير — تبغى التفاصيل؟ 🌙`
  ];
  reply = positiveReplies[Math.floor(Math.random() * positiveReplies.length)];
  should_dm = false;
}
// Question
else if (textLower.match(/ايش|وش|شنو|ما هو|ماهو|يعني|معنى|فكرة/)) {
  intent = 'question';
  reply = `@${username} تمعّن = رحلة قرآنية 28 يوم مستوحاة من كتاب مدينة المعنى — تبغى أشرحلك أكثر بالخاص؟ 📖`;
  should_dm = true;
}
// Objection / doubt
else if (textLower.match(/غالي|مو مقتنع|ما أدري|صعب|ما أقدر/)) {
  intent = 'objection';
  reply = `@${username} فيه عرض خاص لأول مرة — أرسلك التفاصيل خاص 🎁`;
  should_dm = true;
}
// General engagement
else {
  intent = 'general';
  const generalReplies = [
    `@${username} حياك الله 🤍`,
    `@${username} شكراً لتعليقك! 🌙`,
    `@${username} الله يبارك فيك ✨`
  ];
  reply = generalReplies[Math.floor(Math.random() * generalReplies.length)];
  should_dm = false;
}

return {
  json: {
    ...$json,
    intent,
    reply,
    should_dm,
    reply_generated_at: new Date().toISOString()
  }
};

