// Story mention or DM → forward to Warda
const event = $json;

if (event.event_type === 'dm') {
  // Forward DM to Warda Sales workflow
  return {
    json: {
      forward_to: 'warda',
      message: event.comment_text,
      sender: event.commenter_id,
      sender_username: event.commenter_username,
      source: 'instagram_dm',
      timestamp: event.timestamp
    }
  };
}

if (event.event_type === 'story_mention') {
  return {
    json: {
      forward_to: 'engagement_log',
      type: 'story_mention',
      user_id: event.commenter_id,
      username: event.commenter_username,
      action: 'reply_story_with_thanks',
      timestamp: event.timestamp
    }
  };
}

return { json: { forward_to: 'none' } };

